class Admin_Model_ProductLang extends Admin_Model_Base_ProductLang {


    /**
     * @param Doctrine_Connection|null $conn
     */
    public function save(Doctrine_Connection $conn = null) {
        $this->SearchName = utf2ascii($this->Name);
        $originalSlug = $this->slug;

        parent::save($conn);

        Product::updateProductDateTime($this->Product_ID);
        $modifiedSlug = $this->slug;
        if($originalSlug != $modifiedSlug) {
            try {
                if($originalSlug)
                ProductSlugHistory::addSlugHistory($this->Product_ID, $originalSlug);
            } catch (Exception $e) {
                // do nothing
            }
        }
    }


    public static function getProductNameByIDAndLanguageID(int $productID, int $langID) {
        $query= Doctrine_Query::create();
        $query->from('Admin_Model_ProductLang');
        $query->where('Product_ID=?', $productID);
        $query->andWhere('Language_ID=?', $langID);
        $fetch = $query->fetchOne();
        if($fetch) {
            return $fetch->Name;
        }
        return null;
    }

    public static function getProductLang(int $productID, int $langID = 1) {
        $query= Doctrine_Query::create();
        $query->from('Admin_Model_ProductLang');
        $query->where('Product_ID=?', $productID);
        $query->andWhere('Language_ID=?', $langID);
        return $query->fetchOne();
    }

}